queries.sparql:
PREFIX : <http://ambrosia.example.org/hospitality#>
PREFIX p: <http://ambrosia.example.org/hospitality/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?type WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasFacilities ?child ; p:hasAirports ?parent . } GROUP BY ?child }
  ?child p:Type ?type .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Airports } }
  FILTER(?nf = ?total)
}

ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/hospitality#>
PREFIX p: <http://ambrosia.example.org/hospitality/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE scope {
  distributive: { SELECT ?name ?type WHERE {
  ?airports_facilities a :Airports_Facilities .
  ?facilities a :Facilities .
  ?airports_facilities p:hasFacilities ?facilities .
  ?airports a :Airports .
  ?airports_facilities p:hasAirports ?airports .
  ?airports p:name ?name .
  ?facilities p:Type ?type .
} }
  collective: { SELECT ?type WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasFacilities ?child ; p:hasAirports ?parent . } GROUP BY ?child }
  ?child p:Type ?type .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Airports } }
  FILTER(?nf = ?total)
} }
}
